        await module.InvokeVoidAsync(InitializeMethod, dotNetRef);
    }

    public async ValueTask SaveAsync(string content)
    {
        var module = await GetModuleAsync();
        await module.InvokeVoidAsync(SaveMethod, content);
    }

    public async ValueTask<string?> LoadAsync()
    {
        var module = await GetModuleAsync();
        return await module.InvokeAsync<string?>(LoadMethod);
    }

    public async ValueTask ClearAsync()
    {
        var module = await GetModuleAsync();
        await module.InvokeVoidAsync(ClearMethod);
    }

    public async ValueTask DisposeAsync()
    {
        try
